import React from "react";
import { motion } from "framer-motion";
import { Clock, MapPin, Package, Check } from "lucide-react";

export default function FoodCard({ item, onComplete }) {
  const isExpiringSoon = () => {
    if (!item.expiry) return false;
    const expiryDate = new Date(item.expiry);
    const now = new Date();
    const diffHours = (expiryDate - now) / (1000 * 60 * 60);
    return diffHours < 12 && diffHours > 0;
  };

  return (
    <motion.div
      layout
      initial={{ opacity: 0, scale: 0.95 }}
      animate={{ opacity: 1, scale: 1 }}
      className="card flex flex-col md:flex-row items-stretch gap-6 overflow-hidden relative group"
    >
      {isExpiringSoon() && (
        <div className="absolute top-0 right-0 bg-rose-500 text-white text-[10px] font-bold px-3 py-1 rounded-bl-lg uppercase tracking-wider z-10">
          Expiring Soon
        </div>
      )}

      <div className="md:w-48 h-48 bg-white/5 rounded-lg flex items-center justify-center border border-white/5 group-hover:border-white/10 transition-colors">
        <Package className="w-12 h-12 text-white/20 group-hover:text-primary/40 transition-colors" />
      </div>

      <div className="flex-1 flex flex-col justify-between py-1">
        <div>
          <div className="flex justify-between items-start mb-2">
            <h3 className="text-xl font-bold text-white mb-0">{item.name}</h3>
            <span className="text-sm px-2 py-1 bg-primary/20 text-primary-light rounded-md border border-primary/30">
              {item.type}
            </span>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4">
            <div className="flex items-center gap-2 text-sm text-white/60">
              <Clock className="w-4 h-4 text-primary" />
              <span>Expires: {new Date(item.expiry).toLocaleString()}</span>
            </div>
            <div className="flex items-center gap-2 text-sm text-white/60">
              <MapPin className="w-4 h-4 text-primary" />
              <span>{item.location}</span>
            </div>
            <div className="flex items-center gap-2 text-sm text-white/60">
              <Package className="w-4 h-4 text-primary" />
              <span>Quantity: {item.quantity}</span>
            </div>
          </div>
        </div>

        <div className="mt-6 flex gap-3">
          <button
            onClick={() => onComplete(item.id)}
            className="primary flex items-center gap-2"
          >
            <Check className="w-4 h-4" />
            Mark as Collected
          </button>
        </div>
      </div>
    </motion.div>
  );
}
